  {"feature_slug": "../etc/passwd", "category": "new_event", "description": "should be sanitized", "gap_score": 10, "affected_skills": [], "reference_changelog_line": "test"}
]
EOF

CLAUDE_CODE_OAUTH_TOKEN=fake-token \
CC_TRIAGE_FIXTURE="$FIXTURE" \
